var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로…… 정녕 너란 말이냐?","JPN":"マエストロ……本当に貴様なのか？","ENG":"Maestra... Could it really be you?","TWN":"你真的……是指揮家嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지난날에 대한 속죄 따윈 없이! 인간의 허물을 쓰고 숨어 지냈단 말이냐!","JPN":"過ぎし日への償いすら無く！　人間の皮を被り隠れていたというのか！","ENG":"Avoiding judgement for your sins, you’ve been hiding under the disguise of a human!","TWN":"你不但沒有為以前的事贖罪！甚至還偽裝成人的樣子躲起來嗎！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러니까 몇 번이나 아니라고 했잖아!","JPN":"だから何度も違うって言ってるでしょう！","ENG":"I told you several times!","TWN":"我不是一直跟你說我不是嗎！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"용병 씨! 뭔가 꿍꿍이를 꾸미고 있는 거 아니었어?!","JPN":"傭兵さん！　なんか策があるんじゃなかったの！？","ENG":"Ms. Mercenary! Don’t you have anything else up your sleeve?","TWN":"傭兵小姐！你不是有在打什麼算盤嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래, 슬슬 끝나지 않았으려나?","JPN":"そうよ、そろそろできたんじゃないかしら？","ENG":"It shall be ready soon.","TWN":"是啊，但好像還需要點時間？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"접속 완료! 현재 교전 중인 좌표로 포신 방향 조정 중입니다!","JPN":"接続完了！　現在交戦中の座標に砲身の方向を調整しています！","ENG":"Hacking Complete! Aiming the artillery to the coordinates of the engagement!","TWN":"連線完畢！現在砲身的方向正調整為交戰中的座標！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"세상에, 기체를 이렇게나 함부로 다루면 어떡한담?","JPN":"まあ、機体をあんなむやみに扱っちゃダメでしょうに。","ENG":"Oh my, the body is in such poor condition though...","TWN":"我的天啊，這樣任意操控機體沒問題嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"잔소리할 시간 없다! 부전대장님이 두 동강 나기 전에 서둘러!","JPN":"小言を言っている場合か！　副戦隊長が真っ二つになる前に急げ！","ENG":"This is no time to nitpick! Hurry up before the Deputy Commander is sliced in two!","TWN":"現在沒時間廢話這些！在副戰隊長斷成兩截之前，動作快！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어머나! 죄송해요, 오랜만에 봤더니 그만!","JPN":"あらまあ！　ごめんなさい、久しぶりでしたのでつい！","ENG":"I'm sorry... It’s just been so long since I did this!","TWN":"抱歉抱歉！馬上來！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"방렬 완료! 에너지 충전까지 10, 9, 8, 7……!","JPN":"放列完了！　エネルギー充電まで10、9、8、7……！","ENG":"In position! Charging energy for a full power shot. 10, 9, 8, 7…!","TWN":"放列完畢！充能倒數10、9、8、7……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"물러나, 폭주족! 4종 침식체에게도 유효타인 포격이야!","JPN":"下がれ、暴走族！　第4種侵食体にも効く砲撃だ！","ENG":"Get back! The artillery blast is on the level of a Category 4 Corrupted Object!","TWN":"退下，暴走族！這個火力可是足以對付4類侵蝕體！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭐? 하늘에서 뚝 떨어진 것도 아닌데 그런 무기가 우리나라에 있을 리가……!","JPN":"は？　空から落ちたわけでもないし、そんな武器がこの国にあるわけ……！","ENG":"What? Where did such a weapon come from? No way it’s from our country, did it just fall out of the sky or something...?","TWN":"什麼？這是從天上掉下來的嗎？我們國家怎麼可能有這種武器……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 저런 괴물은 예전부터 있었어? 허튼 소리 말고 뛰어!","JPN":"それじゃあ、あんな化け物は昔からいたとでも言うの？　いいから走って！","ENG":"No way that monster could have come from your country. Anyways, stop talking and... Run!","TWN":"那從以前就有那個怪物嗎？廢話少說，快跑！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"입자포! 최대 출력으로 발사합니다!!","JPN":"粒子砲！　最大出力で発射します！！","ENG":"Particle gun! Fire at full power!","TWN":"粒子砲！以最大火力發射！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_ARONDIGHT_SKILL_LOOP"},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……음?","JPN":"……うむ？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"콜록! 콜록!","JPN":"ゲホ、ゲホ！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무슨 고철을 대포라고 세워 뒀나 했더니……. 이런 거였어?","JPN":"スクラップを大砲よろしく立てて、何のつもりかと思ったら……こういう物だったの？","ENG":"I was wondering about that crappy looking artillery parked there... Never thought it could do this!","TWN":"我還想誰把廢鐵當作大砲放在這裡……原來是這樣？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아야……?","JPN":"レア……？","ENG":"Leah...?","TWN":"蕾亞……？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아야!! 얘야, 어디 있니! 레아아!!","JPN":"レア！！　私の子、どこにいるの！　レア！！","ENG":"Leah!! Where are you, Leah!!","TWN":"蕾亞！我的女兒，你在哪裡！蕾亞！！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니! 바닥에 번개가 튀고 있어요! 다가가면 다칠 거예요!","JPN":"おばさん！　床にプラズマが残ってます！　近づいたら怪我しますよ！","ENG":"Madam! The ground is still electrified! You’ll get hurt if you try to get close!","TWN":"伯母！閃電打在地上！太靠近會受傷的！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"*Huff… Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"어때? 해치웠어?","JPN":"どう？　やっつけた？","ENG":"Well? Did that do it?","TWN":"怎麼樣？有幹掉她嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아니. 스스로 물러난 모양이야.","JPN":"いいえ。自ら下がったようね。","ENG":"No. It looks like she just decided to withdraw herself.","TWN":"沒有，她好像是自己撤退的。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 생각하는 이유는?","JPN":"そう思う根拠は？","ENG":"And why do you think that?","TWN":"為什麼這麼說？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"에스타크의 입자포는 이런 식으로 잔여 에너지를 남기지 않거든.","JPN":"エスタークの粒子砲はこんな風にエネルギーを残さないの。","ENG":"Estaque’s particle guns don’t leave this type of residual energy.","TWN":"艾斯塔克的粒子砲，不會以這種方式保留能量。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아마 접촉 직전에 포격을 맞받아쳤으려나. 신입들을 겁 줄 정도이긴 하네.","JPN":"たぶん体にあたる寸前に砲撃を撃ち返したんでしょうね。新入りが怖がるわけだわ。","ENG":"She probably met the barrage with that of her own to cancel out the attack. Probably could scare the newbies.","TWN":"應該是在接觸前就先回擊砲擊，就像給新人下馬威一樣。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도, 일단은 목숨을 건졌단 뜻이지?","JPN":"でも、とりあえず命拾いはしたってこと？","ENG":"But still...our lives are safe for now, right?","TWN":"總之我們算是保住一命吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 정말 죽이려고 했는지는 의문이지만.","JPN":"どうかしら。本当に殺そうとしたのか疑問だけど。","ENG":"Well. I doubt she was truly trying to kill us, but...","TWN":"是嗎？我是有點懷疑，她當初真的有想殺你嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"당사자 앞에서 못하는 소리가 없으시네, 용병 씨.","JPN":"本人の前でよく言うね、傭兵さん。","ENG":"You say everything, Ms. Mercenary. I almost died.","TWN":"傭兵小姐，你在當事人面前，還真是什麼話都敢說呢。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"상공에서 관측했을 때는 부상자만 나왔지, 사망자는 없었어.","JPN":"上空から観測した時には怪我人だけで、死亡者はなかったの。","ENG":"Observing in the air, there were no casualties, only injuries.","TWN":"因為我們在上空監測時，只有出現傷者，沒有人死掉。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"말도 안 돼. 이런 난장판을 만들어 놨는데……. 그게 가능하다고?","JPN":"そんな。こんな修羅場で……あり得ることなの？　それ。","ENG":"No way... With this much destruction... Is that even possible?","TWN":"這怎麼可能！她搞得這麼嚴重……這有可能嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"바꿔 말하면 그래서 우리가 올 때까지 살아 있었던 걸지도 모르지.","JPN":"逆に言えば、だから私たちが来るまで生き延びられたのかも知れないね。","ENG":"In other words, she let you live on purpose.","TWN":"換句話說，或許她在我們來之前都還活著。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그리고 알렉스라고 불러. 용병 씨처럼 아무래도 좋은 호칭은 그닥 마음에 안 들더라.","JPN":"あと、アレックスって呼んで。「傭兵さん」みたいなどうでもいい呼び方はあまり気に入らないの。","ENG":"And call me Alex. I can’t say I like being called Ms. Mercenary.","TWN":"還有，你叫我雅蕾克絲吧。傭兵小姐這個稱呼我不是很喜歡。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"좋아. 알렉스 씨. 제때 와 줘서 고마웠어.","JPN":"わかった。アレックスさん。危ないところをありがとう。","ENG":"Okay! Thank you so much for coming in time, Alex.","TWN":"好，雅蕾克絲，謝謝你們及時趕到。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 인사성이 바르네. 우리 애들도 본받아야겠는걸.","JPN":"ふふっ。礼儀正しいね。ウチの子どもたちも見習って欲しいわ。","ENG":"Fuu fuu. So courteous. My kids could learn a thing or two from you.","TWN":"呵呵，很有禮貌喔！我們的人也該好好學學！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님. 저길 보십시오. 정부군이 도착한 것 같습니다.","JPN":"副戦隊長。あれを見てください。政府軍が来たようです。","ENG":"Deputy Commander. Over there. Looks like the government troops have arrived.","TWN":"副戰隊長，你看，好像是政府軍的人。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L26_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……이런. 보고는 들었지만 피해가 심각하군.","JPN":"……おやおや。報告には聞いていたが、ひどい状態だな。","ENG":"...Unbelievable. I read the reports, but the damage is far worse than I could have imagined.","TWN":"……怎麼會這樣？雖然有收到報告，但情況未免太慘烈！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"너무 늦으셨어요. 주범은 이미 사라진 뒤입니다.","JPN":"遅すぎです。主犯はすでに姿を消しました。","ENG":"You’re too late. The enemy has already disappeared.","TWN":"你們動作太慢了，犯人都跑了才出現。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트, 자네도 여기 있었군.","JPN":"レヴナント、君もここにいたのか。","ENG":"Ah, Revenant. I see you are here as well.","TWN":"亡靈，原來你也在這裡。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"제가 사는 동네 코앞에서 일이 터졌으니까요. 불미스럽게 휘말리기도 했습니다만.","JPN":"私が住んでる街のすぐ近くで状況が発生しましたから。あいにく巻き込まれもしましたけど。","ENG":"It happened right in front of my neighborhood. I had no choice but to get involved.","TWN":"事情就發生在我住的地方而已，我只好淌這個渾水。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그런데…… 군이 대응할 일에 왜 국장님께서 동행하셨죠?","JPN":"ところで……軍が対応すべきことに、どうして局長が同行したんですか？","ENG":"But... Why are you with the troops?","TWN":"不過……這不是軍隊要處理的事嗎？為何部長會一起行動？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래. 이미 이렇게까지 일이 커졌으니 복잡하게 돌아서 갈 필요는 없겠군.","JPN":"そうか。もうここまで事が大きくなっているとすると、複雑に回りくどく言う必要もないな。","ENG":"Well. With the situation having gotten this bad, I suppose we can just do this openly.","TWN":"嗯，既然事情都已經鬧大，那我也沒必要再跟你兜圈子。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트. 아니, 레아 슈나이더.","JPN":"レヴナント。いや、レア・シュナイダー。","ENG":"Revenant, or rather, Leah Schneider.","TWN":"亡靈，不，蕾亞·修奈德，"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네의 반역죄 혐의에 대해 조사해야겠어.","JPN":"君の反逆罪の容疑について調査する。","ENG":"You are being investigated for charges of treason.","TWN":"我們懷疑你觸犯叛國罪，要對你進行調查！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……반역죄요?","JPN":"……反逆罪？","ENG":"...Treason?","TWN":"……叛國罪？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요! 지금 뭐라고……!","JPN":"待ってください！　今なんて……！","ENG":"Wait a second! What did you just say?","TWN":"等等！你說什麼……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네 어머니도 계신데, 시끄럽게 굴지 말고 조용히 처리하지.","JPN":"君の親御さんもここにいることだ。騒がず、静かに処理しよう。","ENG":"Remember, your mother is here. Don’t make a fuss and come quietly.","TWN":"你媽媽也在，別大聲嚷嚷，乖乖跟我們走吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"진위를 판별하는 데 그렇게 오래 걸리지 않을 거야.","JPN":"真偽を明らかにするのにそう長くはかからないだろうさ。","ENG":"It won’t take long to find the truth of the matter.","TWN":"到底是真是假，很快就會水落石出的。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};